<?php
 declare(strict_types=1); namespace League\CommonMark\Extension\Footnote\Event; use League\CommonMark\Event\DocumentParsedEvent; use League\CommonMark\Extension\Footnote\Node\FootnoteRef; use League\CommonMark\Reference\Reference; final class NumberFootnotesListener { public function onDocumentParsed(DocumentParsedEvent $event): void { $document = $event->getDocument(); $walker = $document->walker(); $nextCounter = 1; $usedLabels = []; $usedCounters = []; while ($event = $walker->next()) { if (!$event->isEntering()) { continue; } $node = $event->getNode(); if (!$node instanceof FootnoteRef) { continue; } $existingReference = $node->getReference(); $label = $existingReference->getLabel(); $counter = $nextCounter; $canIncrementCounter = true; if (\array_key_exists($label, $usedLabels)) { $counter = $usedCounters[$label]; $label = $label . '__' . ++$usedLabels[$label]; $canIncrementCounter = false; } $newReference = new Reference( $label, $existingReference->getDestination(), (string) $counter ); $node->setReference($newReference); $document->getReferenceMap()->addReference($newReference); if (false === $document->getData($existingReference->getDestination(), false)) { $document->data[$existingReference->getDestination()] = []; } $document->data[$existingReference->getDestination()][] = $newReference; $usedLabels[$label] = 1; $usedCounters[$label] = $nextCounter; if ($canIncrementCounter) { $nextCounter++; } } } } 